// Extract Exa data - try to find company website from search results
const results = $input.first().json.results || [];
const originalRecord = $('Process One at a Time').first().json;
const companyName = originalRecord['Company Name'].toLowerCase();

// Find the most likely company website
let bestMatch = null;
for (const result of results) {
  const url = result.url || '';
  const title = (result.title || '').toLowerCase();

  // Skip social media, news sites, directories
  if (url.includes('linkedin.com') || 
      url.includes('facebook.com') || 
      url.includes('twitter.com') ||
      url.includes('wikipedia.org') ||
      url.includes('bloomberg.com') ||
      url.includes('crunchbase.com') ||
      url.includes('zoominfo.com')) {
    continue;
  }

  // Prefer if company name appears in domain or title
  const domain = new URL(url).hostname.replace('www.', '');
  if (title.includes(companyName) || domain.includes(companyName.split(' ')[0].toLowerCase())) {
    bestMatch = result;
    break;
  }

  if (!bestMatch) bestMatch = result;
}

let domain = '';
let linkedIn = '';

if (bestMatch) {
  try {
    domain = new URL(bestMatch.url).hostname.replace('www.', '');
  } catch (e) {}
}

// Also look for LinkedIn in results
const linkedInResult = results.find(r => r.url?.includes('linkedin.com/company'));
if (linkedInResult) {
  linkedIn = linkedInResult.url;
}

return [{
  json: {
    recordId: originalRecord.id,
    companyName: originalRecord['Company Name'],
    enrichedData: {
      'Company Domain': domain,
      'Website': bestMatch ? bestMatch.url : '',
      'LinkedIn URL': linkedIn
    },
    source: 'exa',
    exaRaw: bestMatch
  }
}];

// No enrichment data found from any source
const originalRecord = $('Process One at a Time').first().json;

return [{
  json: {
    recordId: originalRecord.id,
    companyName: originalRecord['Company Name'],
    enrichedData: {},
    source: 'none',
    status: 'failed',
    notes: 'No data found from Apollo or Exa'
  }
}];

// Merge enrichment data and determine completeness
const input = $input.first().json;
const enrichedData = input.enrichedData || {};

// Define required fields for "complete" status
const requiredFields = ['Company Domain', 'Industry', 'Employee Count'];
const contactFields = ['Main Phone', 'Main Email', 'Address'];

// Count how many required fields are filled
const filledRequired = requiredFields.filter(f => enrichedData[f] && enrichedData[f] !== '').length;
const filledContact = contactFields.filter(f => enrichedData[f] && enrichedData[f] !== '').length;

let status = 'failed';
if (filledRequired >= 2 || (filledRequired >= 1 && filledContact >= 1)) {
  status = 'complete';
} else if (filledRequired >= 1 || Object.keys(enrichedData).some(k => enrichedData[k])) {
  status = 'partial';
}

// Build notes
let notes = [];
if (input.source !== 'none') {
  notes.push(`Primary source: ${input.source}`);
}
if (status === 'partial') {
  const missing = requiredFields.filter(f => !enrichedData[f] || enrichedData[f] === '');
  if (missing.length > 0) {
    notes.push(`Missing: ${missing.join(', ')}`);
  }
}
if (input.notes) {
  notes.push(input.notes);
}

return [{
  json: {
    recordId: input.recordId,
    companyName: input.companyName,
    fieldsToUpdate: {
      ...enrichedData,
      'Enrichment Source': input.source === 'none' ? '' : input.source,
      'Enrichment Status': status,
      'Enriched Date': new Date().toISOString(),
      'Enrichment Notes': notes.join('. ') || null
    }
  }
}];
